+        )
+        .await
+        {
+            Outcome::Ok(v) => v,
+            other => panic!("outbound failed: {other:?}"),
+        }
+    });
+
+    // RedFox sends: msg 2, 4, 7
+    assert_eq!(
+        page.entries.len(),
+        3,
+        "RedFox should have 3 outbound messages"
+    );
+    assert_eq!(page.stats.outbound_count, 3);
+    assert_eq!(page.stats.inbound_count, 0);
+}
