+        "\u{FFFF}",
+        "\u{1F600}\u{1F600}\u{1F600}",
+        "\u{202E}dlrow olleh",
+        "Привет мир",
+        "你好世界",
+        "a\u{0308}",                // combining diaeresis
+        "\u{200B}\u{200B}\u{200B}", // zero-width spaces
+    ];
+
+    for input in unicode_inputs {
